#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <functional>

// Forward declaration of the user's main function (renamed for testing)
// The test harness will rename the student's `main` to `user_main`.
extern int user_main();

// Function to capture stdout
std::string capture_stdout(std::function<void()> func) {
    std::stringstream ss;
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cout.rdbuf(ss.rdbuf());
    func();
    std::cout.rdbuf(old_cout);
    return ss.str();
}

// Function to simulate stdin
void simulate_stdin(const std::string& input_str) {
    std::stringstream ss_in(input_str);
    std::cin.rdbuf(ss_in.rdbuf());
}

int main() {
    std::vector<std::pair<std::string, std::string>> test_cases = {
        { "5", "Please enter a non-negative integer: The factorial of 5 is 120.\n" },
        { "20", "Please enter a non-negative integer: The factorial of 20 is 2432902008176640000.\n" },
        { "21", "Please enter a non-negative integer: The factorial of 21 is -8128291625829987328.\n" },
        { "-3\n7", "Please enter a non-negative integer: Invalid input. Please enter a non-negative integer: The factorial of 7 is 5040.\n" }
    };

    int passed_tests = 0;
    for (size_t i = 0; i < test_cases.size(); ++i) {
        std::string input = test_cases[i].first;
        std::string expected_output = test_cases[i].second;

        std::streambuf* old_cin = std::cin.rdbuf(); // Save original cin buffer

        simulate_stdin(input);
        std::string actual_output = capture_stdout(user_main);

        std::cin.rdbuf(old_cin); // Restore original cin buffer

        if (actual_output == expected_output) {
            passed_tests++;
        } else {
            // For debugging: std::cerr << "Test " << i + 1 << " Failed. Input: " << input << ", Expected: " << expected_output << ", Actual: " << actual_output << std::endl;
        }
    }
    return passed_tests == test_cases.size() ? 0 : 1;
}
